import { useEffect, useRef, useState } from "react";
import { Link } from "react-router-dom";
import { useAnimateOnScroll } from "../../hooks/useAnimateOnScroll";
import "./MyMap.scss";

let googleMapsPromise;
let googleMapsResolve;

function loadGoogleMaps(apiKey) {
    if (googleMapsPromise) return googleMapsPromise;

    googleMapsPromise = new Promise((resolve, reject) => {
        googleMapsResolve = resolve;

        if (document.getElementById("google-maps-script")) {
            resolve(window.google.maps);
            return;
        }

        const script = document.createElement("script");
        script.id = "google-maps-script";
        script.src = `https://maps.googleapis.com/maps/api/js?key=${apiKey}&libraries=marker&callback=initGoogleMaps&loading=async`;
        script.async = true;
        script.defer = true;

        script.onerror = () => {
            console.error("Failed to load Google Maps script.");
            googleMapsPromise = null;
            reject("Google Maps script failed to load.");
        };

        document.head.appendChild(script);
    });

    return googleMapsPromise;
}

window.initGoogleMaps = () => {
    if (googleMapsResolve) {
        googleMapsResolve(window.google.maps);
    }
};

function MyMap() {
    const mapRef = useRef(null);
    const [sectionRef, isVisible] = useAnimateOnScroll({
        threshold: 0.1,
        rootMargin: "50px",
    });
    const [shouldLoadMap, setShouldLoadMap] = useState(false);
    const apiKey = import.meta.env.VITE_GOOGLE_MAPS_API_KEY;

    useEffect(() => {
        if (isVisible) {
            setShouldLoadMap(true);
        }
    }, [isVisible]);

    useEffect(() => {
        if (!shouldLoadMap) {
            return undefined;
        }

        async function initializeMap() {
            if (!apiKey) {
                console.error("Google Maps API key is missing.");
                if (mapRef.current) {
                    mapRef.current.innerHTML = "<p>Google Maps API key is missing.</p>";
                }
                return;
            }

            try {
                await loadGoogleMaps(apiKey);

                const mapOptions = {
                    center: { lat: -6.163657188415527, lng: 39.18870162963867 },
                    zoom: 14,
                    mapId: "f9d217ab22987daf",
                };

                const map = new window.google.maps.Map(mapRef.current, mapOptions);

                if (window.google.maps.marker?.AdvancedMarkerElement) {
                    new window.google.maps.marker.AdvancedMarkerElement({
                        position: mapOptions.center,
                        map: map,
                        title: "My location",
                    });
                } else {
                    console.error("AdvancedMarkerElement is not available.");
                }
            } catch (error) {
                console.error("Error initializing map:", error);
                if (mapRef.current) {
                    mapRef.current.innerHTML = "<p>Failed to load the map. Please try again later.</p>";
                }
            }
        }

        initializeMap();
    }, [apiKey, shouldLoadMap]);

    return (
        <section
            ref={sectionRef}
            className={`home-map ${isVisible ? "animate" : ""}`}
        >
            <div className="home-map__layout">
                <div className="home-map__copy">
                    <p className="home-map__eyebrow">Plan with a local base</p>
                    <h2 className="home-map__title">Find Destination Paradise</h2>
                    <p className="home-map__description">
                        We are based in Zanzibar and help travelers shape relaxed, memorable days with
                        booking support that feels personal from the first inquiry.
                    </p>
                    <ul className="home-map__highlights">
                        <li>Stone Town-based local coordination</li>
                        <li>Hotel and timing support for excursion days</li>
                        <li>Booking requests handled around your trip plans</li>
                    </ul>
                    <Link to="/booking" className="home-map__button">
                        Start a Booking Request
                    </Link>
                </div>
                <div className="home-map__media">
                    <div ref={mapRef} className="home-map__frame">
                        {!shouldLoadMap && (
                            <p>Interactive map loads when you scroll to this section.</p>
                        )}
                    </div>
                </div>
            </div>
        </section>
    );
}

export default MyMap;
